import { CommonModule } from '@angular/common';
import { Component, Input } from '@angular/core';
import { MisterXLogEntry } from '../../core/models/player.model';

@Component({
  selector: 'app-move-log',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './move-log.component.html',
  styleUrl: './move-log.component.scss'
})
export class MoveLogComponent {
  @Input() entries: MisterXLogEntry[] = [];

  transportSymbol(entry: MisterXLogEntry): string {
    if (!entry.transportRevealed) return '?';
    switch (entry.transportUsed) {
      case 'Taxi': return 'T';
      case 'Bus': return 'B';
      case 'U-Bahn': return 'U';
      case 'Boot': return '~';
      default: return '?';
    }
  }
}
<div class="fahrtentafel">
  <div class="fahrtentafel__title">Fahrtentafel · Mister X</div>
  <div class="fahrtentafel__grid">
    <div
      class="fenster"
      *ngFor="let entry of entries"
      [class.fenster--reveal]="entry.revealedStation !== null"
    >
      <span class="fenster__round">{{ entry.round }}</span>
      <span class="fenster__symbol">{{ transportSymbol(entry) }}</span>
      <span class="fenster__station" *ngIf="entry.revealedStation !== null">
        {{ entry.revealedStation }}
      </span>
    </div>
    <div class="fenster fenster--empty" *ngIf="entries.length === 0">
      Noch keine Züge
    </div>
  </div>
</div>
